import React, { useState } from 'react';
import axios from 'axios';
import '../styles/ResumeUpload.css';

function ResumeUpload({ jobs, selectedJob, onResumeUploaded }) {
  const [formData, setFormData] = useState({
    candidateName: '',
    email: '',
    phone: '',
    jobId: selectedJob || ''
  });
  const [file, setFile] = useState(null);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState({ type: '', text: '' });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      const allowedTypes = ['application/pdf', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
      if (!allowedTypes.includes(selectedFile.type)) {
        setMessage({ type: 'error', text: 'Only PDF and DOCX files are allowed' });
        setFile(null);
        e.target.value = '';
        return;
      }
      if (selectedFile.size > 10485760) { // 10MB
        setMessage({ type: 'error', text: 'File size must be less than 10MB' });
        setFile(null);
        e.target.value = '';
        return;
      }
      setFile(selectedFile);
      setMessage({ type: '', text: '' });
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!file) {
      setMessage({ type: 'error', text: 'Please select a resume file' });
      return;
    }

    setLoading(true);
    setMessage({ type: '', text: '' });

    try {
      const uploadData = new FormData();
      uploadData.append('resume', file);
      uploadData.append('candidateName', formData.candidateName);
      uploadData.append('email', formData.email);
      uploadData.append('phone', formData.phone);
      uploadData.append('jobId', formData.jobId);

      const response = await axios.post(
        'http://localhost:5000/api/resumes/upload',
        uploadData,
        {
          headers: {
            'Content-Type': 'multipart/form-data'
          }
        }
      );

      if (response.data.success) {
        setMessage({ type: 'success', text: 'Resume uploaded successfully!' });
        setFormData({
          candidateName: '',
          email: '',
          phone: '',
          jobId: ''
        });
        setFile(null);
        document.getElementById('resume-file').value = '';
        if (onResumeUploaded) onResumeUploaded();
      }
    } catch (error) {
      setMessage({ 
        type: 'error', 
        text: error.response?.data?.message || 'Error uploading resume' 
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="resume-upload-container">
      <h2>Upload Your Resume</h2>
      
      {message.text && (
        <div className={`message ${message.type}`}>
          {message.text}
        </div>
      )}

      <form onSubmit={handleSubmit} className="resume-form">
        <div className="form-group">
          <label htmlFor="candidateName">Full Name *</label>
          <input
            type="text"
            id="candidateName"
            name="candidateName"
            value={formData.candidateName}
            onChange={handleChange}
            required
            placeholder="Enter your full name"
          />
        </div>

        <div className="form-group">
          <label htmlFor="email">Email *</label>
          <input
            type="email"
            id="email"
            name="email"
            value={formData.email}
            onChange={handleChange}
            required
            placeholder="your.email@example.com"
          />
        </div>

        <div className="form-group">
          <label htmlFor="phone">Phone Number</label>
          <input
            type="tel"
            id="phone"
            name="phone"
            value={formData.phone}
            onChange={handleChange}
            placeholder="+1 (555) 123-4567"
          />
        </div>

        <div className="form-group">
          <label htmlFor="jobId">Select Job Position *</label>
          <select
            id="jobId"
            name="jobId"
            value={formData.jobId}
            onChange={handleChange}
            required
          >
            <option value="">-- Select a Job --</option>
            {jobs.map(job => (
              <option key={job._id} value={job._id}>
                {job.title} - {job.company || 'Company'}
              </option>
            ))}
          </select>
        </div>

        <div className="form-group">
          <label htmlFor="resume-file">Upload Resume (PDF or DOCX) *</label>
          <input
            type="file"
            id="resume-file"
            accept=".pdf,.docx"
            onChange={handleFileChange}
            required
          />
          {file && (
            <div className="file-info">
              ✅ Selected: {file.name} ({(file.size / 1024).toFixed(2)} KB)
            </div>
          )}
        </div>

        <button type="submit" className="submit-btn" disabled={loading}>
          {loading ? '⏳ Uploading...' : '📤 Upload Resume'}
        </button>
      </form>

      <div className="info-box">
        <h3>📋 Instructions:</h3>
        <ul>
          <li>Ensure your resume is in PDF or DOCX format</li>
          <li>File size should not exceed 10MB</li>
          <li>Include relevant skills and experience in your resume</li>
          <li>Your resume will be analyzed by our AI system</li>
        </ul>
      </div>
    </div>
  );
}

export default ResumeUpload;
